const { leadId, email, phone, firstName, source, captureTime } = $json.body;
if (!leadId || !email) throw new Error('Missing data');
const now = new Date();
const captureDate = new Date(captureTime);
const minutesSinceCapture = Math.floor((now - captureDate) / (1000 * 60));
const withinSLA = minutesSinceCapture < 60;
return { leadId, email, phone, firstName, source, minutesSinceCapture, withinSLA, priority: withinSLA ? 'normal' : 'urgent', contactChannels: ['email', 'sms', 'call'] };

const { dealId, email, lastContactDate, touchCount = 0 } = $json.body;
if (!dealId || !email) throw new Error('Missing data');
const daysSinceContact = lastContactDate ? Math.floor((new Date() - new Date(lastContactDate)) / (1000 * 60 * 60 * 24)) : 999;
const sequence = [
  {touch: 1, delay: 0, type: 'email', subject: 'Following up on our conversation'},
  {touch: 2, delay: 2, type: 'sms', message: 'Quick check-in'},
  {touch: 3, delay: 4, type: 'call', subject: 'Need your input'},
  {touch: 4, delay: 7, type: 'email', subject: 'Final offer before deadline'},
  {touch: 5, delay: 10, type: 'sms', message: 'Last chance - ending soon'}
];
const nextTouch = sequence[Math.min(touchCount, sequence.length - 1)];
return { dealId, email, daysSinceContact, currentTouch: touchCount + 1, nextTouch, totalTouches: 5, sequenceComplete: touchCount >= 5 };

const { dealId, lastActivityDate, inactivityThreshold = 7 } = $json.body;
if (!dealId) throw new Error('Missing dealId');
const daysSinceActivity = lastActivityDate ? Math.floor((new Date() - new Date(lastActivityDate)) / (1000 * 60 * 60 * 24)) : 999;
const isStale = daysSinceActivity > inactivityThreshold;
const alertLevel = daysSinceActivity > 30 ? 'critical' : daysSinceActivity > 14 ? 'warning' : 'normal';
return { dealId, daysSinceActivity, isStale, alertLevel, action: isStale ? 'alert_rep' : 'monitor', actionItems: isStale ? ['contact_prospect', 'review_status', 'adjust_strategy'] : [] };

const { dealId, fromStage, toStage, dealValue } = $json.body;
if (!dealId || !toStage) throw new Error('Missing data');
const stages = ['prospect', 'quote', 'negotiation', 'closing', 'won', 'lost'];
const toIndex = stages.indexOf(toStage);
const isValidAdvancement = toIndex > -1;
return { dealId, fromStage, toStage, isValidAdvancement, dealValue, advanceTime: new Date().toISOString(), updatePipeline: isValidAdvancement };

const { dealId, outcome, dealValue, closedDate, repId } = $json.body;
if (!dealId || !outcome) throw new Error('Missing data');
const isWin = outcome === 'won';
const revenueImpact = isWin ? dealValue : 0;
return { dealId, outcome, isWin, dealValue, closedDate: closedDate || new Date().toISOString(), repId, revenueImpact, logTime: new Date().toISOString() };

const { dealId, objectionType, responseGiven } = $json.body;
if (!dealId || !objectionType) throw new Error('Missing data');
const objections = {
  'price': 'Focus on ROI and payment plans',
  'timing': 'Highlight urgency and limited offers',
  'competitor': 'Emphasize unique differentiators',
  'budget': 'Offer flexible pricing options',
  'authority': 'Arrange decision-maker meeting'
};
const suggestedResponse = objections[objectionType] || 'Request more information';
return { dealId, objectionType, suggestedResponse, responseGiven: responseGiven || null, trackingId: `obj_${dealId}_${Date.now()}` };

const { dealId, conversationText } = $json.body;
if (!dealId || !conversationText) throw new Error('Missing data');
const competitors = ['competitor1', 'competitor2', 'competitor3'];
const mentioned = competitors.filter(c => conversationText.toLowerCase().includes(c.toLowerCase()));
const hasCompetitorMention = mentioned.length > 0;
return { dealId, competitorsMentioned: mentioned, hasCompetitorMention, alertLevel: hasCompetitorMention ? 'high' : 'low', action: hasCompetitorMention ? 'escalate_to_manager' : 'continue_normal_process' };

const { dealId, dealValue, winProbability, estimatedCloseDate } = $json.body;
if (!dealId || !dealValue) throw new Error('Missing data');
const probability = winProbability || 0.5;
const weightedValue = dealValue * probability;
const monthToClose = new Date(estimatedCloseDate);
const forecastMonth = monthToClose.toLocaleString('default', {month: 'long', year: 'numeric'});
return { dealId, dealValue, probability, weightedValue, forecastMonth, forecastCategory: weightedValue > 5000 ? 'high' : weightedValue > 1000 ? 'medium' : 'low' };

const { dealId, lostReason, dealValue } = $json.body;
if (!dealId || !lostReason) throw new Error('Missing data');
const reEngagementDays = [30, 60, 90];
const schedule = reEngagementDays.map(d => ({day: d, message: `Checking back in - hope things have changed!`}));
return { dealId, lostReason, dealValue, reEngagementSchedule: schedule, firstReEngagementDate: new Date(Date.now() + 30*24*60*60*1000).toISOString() };
